def find_redundant_connection(edges):
    """
    Bir grafikteki gereksiz bağlantıyı bulur.

    Args:
        edges: Kenarların bir listesi (u, v) çiftleri olarak temsil edilir.

    Returns:
        Grafikteki gereksiz bağlantı. Grafikte gereksiz bağlantı yoksa, None döndürür.
    """

    def find(parent, i):
        if parent[i] == i:
            return i
        return find(parent, parent[i])

    def union(parent, rank, x, y):
        xroot = find(parent, x)
        yroot = find(parent, y)

        if rank[xroot] < rank[yroot]:
            parent[xroot] = yroot
        elif rank[xroot] > rank[yroot]:
            parent[yroot] = xroot
        else:
            parent[yroot] = xroot
            rank[xroot] += 1

    n = len(edges)
    parent = list(range(n + 1))
    rank = [0] * (n + 1)

    for u, v in edges:
        x = find(parent, u)
        y = find(parent, v)

        if x == y:
            return [u, v]
        else:
            union(parent, rank, x, y)

    return None

if __name__ == '__main__':
    edges = [[1, 2], [1, 3], [2, 3]]
    redundant_edge = find_redundant_connection(edges)
    print(f"Gereksiz bağlantı: {redundant_edge}")

    edges = [[1, 2], [2, 3], [3, 4], [1, 4], [1, 5]]
    redundant_edge = find_redundant_connection(edges)
    print(f"Gereksiz bağlantı: {redundant_edge}")
